#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 13;
struct node
{
	int t, d, l;
} a[MAXN];
int f[(1 << MAXN)];
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	for (int t = read(), n; t; --t)
	{
		n = read();
		memset(f, 0x3f, sizeof f);
		for (int j = 1; j <= n; ++j)
		{
			a[j].t = read(), a[j].d = read(), a[j].l = read();
			f[1 << j - 1] = a[j].t + a[j].l;
		}
		for (int j = 1; j < 1 << n; ++j)
		{
			for (int k = 1; k <= n; ++k)
			{
				if (1 << k - 1 & j)
				{
					if (f[j - (1 << k - 1)] > a[k].t + a[k].d)continue;
					f[j] = min(f[j], max(f[j - (1 << k - 1)], a[k].t) + a[k].l);
				}
			}
		}
		if (f[(1 << n) - 1] == inf)
		{
			puts("NO");
		}
		else
		{
			puts("YES");
		}
	}
	return false;
}
